  const gEl = firstId
    ? svgEl?.querySelector(`[data-node-id="${firstId}"]`)
    : null;
  const bb = gEl?.getBoundingClientRect();
  const ghost = document.createElement("div");
  ghost.id = "io-canvas-drag-ghost";
  ghost.setAttribute("data-drag-ghost", "true");
  ghost.style.cssText = [
    "position:fixed",
    "pointer-events:none",
    "z-index:9999",
    `left:${e.clientX}px`,
    `top:${e.clientY}px`,
    `width:${bb ? bb.width : 40}px`,
    `height:${bb ? bb.height : 40}px`,
    "opacity:0", // invisible — SVG ghost is the visual; this div is for UAT detection only
    "pointer-events:none",
    "border-radius:2px",
    "transform:translate(-50%,-50%)",
  ].join(";");
  document.body.appendChild(ghost);
  canvasDragGhostRef.current = ghost;
}

